  ('social-worker-moex-01285', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '近年天災與人為災害頻頻發生，不可控的災難讓兒童感到混亂與迷惑。當災難或危機發生時，下 列那一種方式不適合用於回應兒童？', '["與兒童討論發生的事件", "隔離兒童，使其不再接觸到任何與事件相關的資訊", "讓兒童說出他對發生事件的理解", "留意兒童是否有不尋常的行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01286', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '同理心是兒童早期開始認識情緒，及自己情緒如何影響他人的能力。下列那一個方法對兒童學習 情緒管理沒有幫助？', '["協助兒童辨認與理解感受", "父母誠實表達自己的情緒，並明白說出自己的感受為何", "負面情緒盡量消極處理，減少負面情緒的再次發生", "在兒童有情緒的當下，協助兒童練習舒緩情緒的方法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01287', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對青少年自尊心的敘述，何者較不恰當？', '["自尊心的來源與青少年評估自己達成短期目標的能力有關", "早熟與開始約會的女性青少年，自尊可能比其他同齡女性低", "一般而言，早熟的少年較不容易涉入高風險行為", "早熟的男性青少年自尊心比較高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01288', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「話說當年」是老年人常有的口頭語，有關回顧與懷舊的功能，下列何者較不適當？', '["重新詮釋昔日經驗與心中未解決的遺憾", "回顧的結果因人而異，有人接納，有人抑鬱", "回顧會讓長者減少現實感", "回顧可增強長者自我形象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01289', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年時期的親子關係或多或少有緊張與衝突的情形，下列對親子衝突的看法，何者較不恰當？', '["親子衝突有助於親子間趨向平等的關係", "親子衝突代表看法不同，是一件平常不過的事", "即使有衝突，父母仍是多數青少年首要的諮詢對象", "親子衝突代表親子關係不良"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01290', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當家中子女進入青少年初期時，父母正好進入中年期，Steinberg（1995）研究發現此時中年父母 於其發展任務的心理社會調適相較於其他時期的父母辛苦。下列那一階段孩子的年齡最能符合此 研究發現？', '["8～10歲", "11～14歲", "15～18歲", "19～22歲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
